// The synthetic ensures has shape `LHS ==> det_set_equal(r1, r2, post1@, post2@)`,
// so the ensures-foralls about post1_self_ and post2_self_ are only hypotheses
// inside the antecedent — they are NOT facts in the outer proof context. We
// branch on the full LHS; inside the then-branch every ensures-conjunct is in
// scope and we prove `post1_self_@ == post2_self_@`, which is the only
// non-trivial part of `det_set_equal` (the unit `r1 == r2` is automatic).
// In the else-branch the implication is vacuously true. The join of the two
// branches gives the conditional fact `LHS ==> post1_self_@ == post2_self_@`,
// which combined with the ensures-LHS at function exit discharges the goal.
if (post1_self_.valid()
    && (forall |ki: KeyIterator<K>|
        #[trigger] KeyIterator::between(*lo, ki, *hi)
            ==> post1_self_@[*ki.get()] == dst@)
    && (forall |ki: KeyIterator<K>|
        !ki.is_end_spec() && !(#[trigger] KeyIterator::between(*lo, ki, *hi))
            ==> post1_self_@[*ki.get()] == pre_self_@[*ki.get()])
    && post2_self_.valid()
    && (forall |ki: KeyIterator<K>|
        #[trigger] KeyIterator::between(*lo, ki, *hi)
            ==> post2_self_@[*ki.get()] == dst@)
    && (forall |ki: KeyIterator<K>|
        !ki.is_end_spec() && !(#[trigger] KeyIterator::between(*lo, ki, *hi))
            ==> post2_self_@[*ki.get()] == pre_self_@[*ki.get()]))
{
    // `valid()` is closed; this lemma is the only way to learn that the view
    // covers all of K, which we need so that map extensionality reduces to
    // pointwise equality at every k: K (and so that `m@[k]` is well-defined).
    post1_self_.valid_implies_complete();
    post2_self_.valid_implies_complete();

    // Pointwise equality at every K. For an arbitrary `k`, build the
    // non-end iterator `ki = { k: Some(k) }`; its open specs give
    // `!ki.is_end_spec()` and `*ki.get() == k`. The case split mentions
    // `KeyIterator::between(*lo, ki, *hi)` in both branches — exactly the
    // trigger of all four ensures-foralls — so they instantiate at this ki.
    assert forall |k: K| #[trigger] post1_self_@[k] == post2_self_@[k] by {
        let ki: KeyIterator<K> = KeyIterator::<K> { k: Some(k) };
        if KeyIterator::between(*lo, ki, *hi) {
            // foralls 1 & 3 fire: post1@[*ki.get()] == dst@ == post2@[*ki.get()],
            // and *ki.get() == k by the open spec of `get_spec`.
        } else {
            // !between, and !ki.is_end_spec() (since ki.k = Some(k));
            // foralls 2 & 4 fire: both posts equal pre@[*ki.get()] there.
        }
    };

    // Both views have full domain and agree pointwise, so they are equal.
    assert(post1_self_@ =~= post2_self_@);
}
